// Do not edit manually. Run the generate-quote command to add entries.

import type { ComponentType } from "react";
import type { Quote } from "@/features/quotes/types";

export interface QuoteRegistryEntry {
  QuoteContent: ComponentType<{ quote: Quote }>;
  QuotePDF: ComponentType<{ quote: Quote }>;
}

export const quoteRegistry: Record<string, QuoteRegistryEntry> = {
  // Entries are added here by the generation pipeline
  // Example: 'abc123xyz': { QuoteContent, QuotePDF }
};
```

When the pipeline runs for quote ID `abc123`, it appends an import and a registry entry:

```typescript
import { QuoteContent as QuoteContent_abc123 } from "./Quote_abc123/QuoteContent";
import { QuotePDF as QuotePDF_abc123 } from "./Quote_abc123/QuotePDF";

export const quoteRegistry: Record<string, QuoteRegistryEntry> = {
  'abc123xyz': { QuoteContent: QuoteContent_abc123, QuotePDF: QuotePDF_abc123 },
};
```

### Step 5: `AiQuoteShell` Component — `src/features/quotes/components/AiQuoteShell.tsx`

This is a thin "chrome" wrapper that adds the PRAGMA header, locale switcher, PDF download link, and Accept button around the bespoke `QuoteContent`. It preserves the existing `QuoteActions` + `acceptQuoteAction` pattern:

```typescript
"use client";

import type { Quote } from "../types";
import type { ComponentType } from "react";
import { QuoteActions } from "./QuoteViewer"; // extract this sub-component or duplicate it
import { useLocale } from "next-intl";
import { Link } from "@/i18n/navigation";
import { useState } from "react";
import { acceptQuoteAction } from "../actions";
import { useRouter } from "@/i18n/navigation";

interface AiQuoteShellProps {
  quote: Quote;
  QuoteContent: ComponentType<{ quote: Quote }>;
}

export function AiQuoteShell({ quote, QuoteContent }: AiQuoteShellProps) {
  const locale = useLocale();
  const router = useRouter();
  const [accepting, setAccepting] = useState(false);

  async function handleAccept() {
    setAccepting(true);
    await acceptQuoteAction(quote.id);
    router.refresh();
  }

  return (
    <div className="min-h-screen bg-grid">
      {/* Standard PRAGMA header with locale switcher */}
      <header className="border-b border-pragma-border bg-pragma-bg/80 backdrop-blur-md">
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex items-center justify-between">
          <span className="font-display text-xl font-bold text-pragma-accent">PRAGMA</span>
          <div className="flex items-center gap-1 text-xs font-medium">
            <Link href={`/quote/${quote.id}`} locale="en" className={`px-2 py-1 rounded transition-colors ${locale === "en" ? "text-pragma-accent" : "text-pragma-muted hover:text-pragma-text"}`}>EN</Link>
            <span className="text-pragma-border">|</span>
            <Link href={`/quote/${quote.id}`} locale="es" className={`px-2 py-1 rounded transition-colors ${locale === "es" ? "text-pragma-accent" : "text-pragma-muted hover:text-pragma-text"}`}>ES</Link>
          </div>
        </div>
      </header>

      {/* Bespoke AI-generated content */}
      <QuoteContent quote={quote} />

      {/* Standard action bar */}
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 pb-12">
        <QuoteActions quote={quote} accepting={accepting} onAccept={handleAccept} />
      </div>

      <footer className="border-t border-pragma-border">
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-6 text-center">
          <p className="text-xs text-pragma-muted">Powered by PRAGMA</p>
        </div>
      </footer>
    </div>
  );
}
```

Note: `QuoteActions` is currently an internal function in `QuoteViewer.tsx`. You either extract it to its own file (`src/features/quotes/components/QuoteActions.tsx`) or duplicate the small component in `AiQuoteShell`. Extraction is cleaner.

### Step 6: Modify Client-Facing Page — `src/app/[locale]/quote/[id]/page.tsx`

```typescript
import { notFound } from "next/navigation";
import { getQuoteById } from "@/features/quotes/lib/queries";
import { QuoteViewer } from "@/features/quotes/components/QuoteViewer";
import { AiQuoteShell } from "@/features/quotes/components/AiQuoteShell";
import { quoteRegistry } from "@/generated-quotes/registry";
import type { Metadata } from "next";

export const metadata: Metadata = {
  robots: { index: false, follow: false },
};

export default async function QuotePage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = await params;
  const quote = await getQuoteById(id);

  if (!quote) notFound();

  if (quote.quoteType === "ai-generated") {
    const entry = quoteRegistry[quote.id];
    if (!entry) notFound(); // Registry not updated yet — should not happen in production
    return <AiQuoteShell quote={quote} QuoteContent={entry.QuoteContent} />;
  }

  return <QuoteViewer quote={quote} />;
}
```

### Step 7: Modify PDF Route — `src/app/api/quote/[id]/pdf/route.ts`

```typescript
// Inside the GET handler, after fetching the quote:
if (quote.quoteType === "ai-generated") {
  const { quoteRegistry } = await import("@/generated-quotes/registry");
  const entry = quoteRegistry[quote.id];
  if (!entry) {
    return NextResponse.json({ error: "PDF template not found" }, { status: 404 });
